import numpy as np
from collections import Counter
import math

class TFIDFVectorizer:
    def __init__(self):
        self.vocabulary_ = {}
        self.idf_ = None

    def fit(self, corpus: list) -> 'TFIDFVectorizer':
        N = len(corpus)
        # Build vocabulary and document frequencies
        df = Counter()
        all_terms = set()
        for doc in corpus:
            unique_terms = set(doc)
            all_terms.update(unique_terms)
            df.update(unique_terms)
        # Sorted vocabulary
        vocab = sorted(all_terms)
        self.vocabulary_ = {term: idx for idx, term in enumerate(vocab)}
        # Smooth IDF
        self.idf_ = np.array([
            math.log((N + 1) / (df[term] + 1)) + 1.0
            for term in vocab
        ])
        return self

    def transform(self, docs: list) -> np.ndarray:
        V = len(self.vocabulary_)
        n = len(docs)
        matrix = np.zeros((n, V))
        for i, doc in enumerate(docs):
            if len(doc) == 0:
                continue
            tf_counts = Counter(doc)
            doc_len = len(doc)
            for term, count in tf_counts.items():
                if term in self.vocabulary_:
                    j = self.vocabulary_[term]
                    tf = count / doc_len
                    matrix[i, j] = tf * self.idf_[j]
        return matrix

    def fit_transform(self, corpus: list) -> np.ndarray:
        self.fit(corpus)
        return self.transform(corpus)
